#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char line[64];
    // consume the rest of the line after T
    fgets(line, sizeof line, stdin);
    while (T-- > 0) {
        // read a non‑empty line containing L and W
        if (!fgets(line, sizeof line, stdin)) break;
        while (strlen(line) == 0 || line[0] == '\n') {
            if (!fgets(line, sizeof line, stdin)) break;
        }
        int L, W;
        if (sscanf(line, "%d %d", &L, &W) != 2) {
            // fallback in case of malformed line
            if (scanf("%d %d", &L, &W) != 2) break;
        }
        printf("%d\n", L * W);
    }
    return 0;
}

